-- Standard Delivery Checklist (49 items)
DO $$ DECLARE cl_id INT;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM checklists WHERE name='Standard Delivery Checklist' AND is_global=TRUE) THEN
    VALUES ('Standard Delivery Checklist', 'delivery', '1.0', NULL, TRUE, NOW())
    RETURNING id INTO cl_id;
  END IF;
END $$;

