-- Project: AAA PDH
DO $$ DECLARE
  proj_id   INT;
  admin_id  INT;
  rvwr_id   INT;
  del_cl_id  INT;
  tec_cl_id  INT;
  del_rv_id  INT;
  del_rv_rpt_id INT;
  tec_rv_id  INT;
  tec_rv_rpt_id INT;
BEGIN
  SELECT id INTO admin_id FROM users WHERE email='admin@reviewbot.com';
  SELECT id INTO rvwr_id  FROM users WHERE email='reviewer@reviewbot.com';

  -- upsert project
  VALUES ('AAA PDH', 'enterprise', 'active', admin_id, NOW())
  ON CONFLICT DO NOTHING;
  SELECT id INTO proj_id FROM projects WHERE name='AAA PDH';

  -- Checklist: AAA PDH — Delivery Checklist
  VALUES ('AAA PDH — Delivery Checklist', 'delivery', '1.0', proj_id, FALSE, NOW())
  RETURNING id INTO del_cl_id;


  -- Review + responses
  VALUES (proj_id, del_cl_id, 'AAA PDH Delivery Review', 'completed', rvwr_id, FALSE, NOW(), NOW(), NOW())
  RETURNING id INTO del_rv_id;


