    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '8.3', 'Financial Health', 'Are margins and utilization aligned with targets and monitored regularly?', 'delivery', 1.0, TRUE, 'Yes', 36, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '8.4', 'Financial Health', 'Are scope / change decisions evaluated for commercial impact before commitment?', 'delivery', 1.0, TRUE, 'Yes', 37, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '8.5', 'Financial Health', 'Are there any forecasted financial risks (overruns, discounts, unapproved change orders)?', 'delivery', 1.0, TRUE, 'No', 38, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '9.1', 'Customer Success & Growth', 'What is the latest CSAT / NPS / qualitative feedback from the customer?', 'delivery', 1.0, TRUE, NULL, 39, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '9.2', 'Customer Success & Growth', 'Is the customer getting measurable value and business outcomes from the engagement?', 'delivery', 1.0, TRUE, 'Yes', 40, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '9.3', 'Customer Success & Growth', 'Are we actively managing key stakeholders and influencing positively at multiple levels?', 'delivery', 1.0, TRUE, 'Yes', 41, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '9.4', 'Customer Success & Growth', 'Are there identified upsell, cross-sell, or expansion opportunities with clear next steps?', 'delivery', 1.0, TRUE, 'Yes', 42, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '9.5', 'Customer Success & Growth', 'Are we building references, success stories, or case studies with customer consent?', 'delivery', 1.0, TRUE, 'Yes', 43, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '10.1', 'Continuous Improvement & Knowledge Management', 'Are regular retrospectives / lessons-learned sessions conducted and actions tracked?', 'delivery', 1.0, TRUE, 'Yes', 44, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '10.2', 'Continuous Improvement & Knowledge Management', 'Are best practices, templates, and checklists reused and improved across sprints / releases?', 'delivery', 1.0, TRUE, 'Yes', 45, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '10.3', 'Continuous Improvement & Knowledge Management', 'Is project knowledge (designs, decisions, FAQs, runbooks) stored in a shared repository and kept current?', 'delivery', 1.0, TRUE, 'Yes', 46, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '10.4', 'Continuous Improvement & Knowledge Management', 'Are metrics (quality, speed, stability, customer KPIs) used to drive continuous improvement?', 'delivery', 1.0, TRUE, NULL, 47, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '10.5', 'Continuous Improvement & Knowledge Management', 'Are transition, handover, and long-term maintainability aspects planned from early stages?', 'delivery', 1.0, TRUE, 'Yes', 48, NOW());
    INSERT INTO checklists (name, type, version, project_id, is_global, created_at)
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '1.1', 'Architecture & Design', 'Who is responsible for the architecture and design ? (If Reflections, who is the named person ? If not Reflections, below questions on architecture will be more for mining and whitespace.)', 'technical', 1.0, TRUE, 'Reflections - Sanju', 0, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '1.2', 'Architecture & Design', 'Is the target architecture documented and up to date (context, container, component, deployment diagrams)? How is the documentation stored, versioned, audited ?', 'technical', 1.0, TRUE, 'Yes', 1, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '1.3', 'Architecture & Design', 'Are HLD and LLD available for all key modules and services?', 'technical', 1.0, TRUE, 'Yes', 2, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '1.4', 'Architecture & Design', 'Are architectural decisions and trade-offs documented and aligned with business and technical requirements?', 'technical', 1.0, TRUE, 'Yes', 3, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '1.5', 'Architecture & Design', 'Is the design modular, loosely coupled, scalable and maintainable?', 'technical', 1.0, TRUE, 'Yes', 4, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '1.6', 'Architecture & Design', 'Are appropriate design patterns and reference architectures consistently applied?', 'technical', 1.0, TRUE, 'Yes', 5, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '1.7', 'Architecture & Design', 'Is there a clear separation of concerns (UI, API, business logic, data, integration, cross-cutting services)?', 'technical', 1.0, TRUE, 'Yes', 6, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '1.8', 'Architecture & Design', 'Is the integration approach (APIs, messaging, microservices, batch/ETL) clearly defined and consistent?', 'technical', 1.0, TRUE, 'Yes', 7, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '1.9', 'Architecture & Design', 'Are cross-cutting concerns (configuration, logging, security, caching, observability) addressed in the design?', 'technical', 1.0, TRUE, 'Yes', 8, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '1.1', 'Architecture & Design', 'Are non-functional requirements (performance, availability, reliability, security, compliance) captured and designed for?', 'technical', 1.0, TRUE, 'Yes', 9, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '1.11', 'Architecture & Design', 'Are chosen technologies and platforms modern, supportable and aligned with enterprise standards and roadmap?', 'technical', 1.0, TRUE, 'Yes', 10, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '1.12', 'Architecture & Design', 'Are deprecated or legacy components identified with a containment or migration plan?', 'technical', 1.0, TRUE, NULL, 11, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '2.1', 'Technical Documentation', 'Is system design and architecture documentation complete, accurate and version-controlled?', 'technical', 1.0, TRUE, 'It is up to date. Older versions of architecture are overwritten', 12, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '2.2', 'Technical Documentation', 'Is API documentation (Swagger/OpenAPI, Postman collections, AsyncAPI, etc.) current and accessible to consumers?', 'technical', 1.0, TRUE, NULL, 13, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '2.3', 'Technical Documentation', 'Are installation, deployment and configuration steps clearly documented and validated on a clean environment?', 'technical', 1.0, TRUE, 'Yes', 14, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '2.4', 'Technical Documentation', 'Is developer onboarding documentation available (local setup, coding standards, workflows)?', 'technical', 1.0, TRUE, 'Yes', 15, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '2.5', 'Technical Documentation', 'Is user, admin and support documentation (SOPs, FAQs, runbooks) available where needed?', 'technical', 1.0, TRUE, NULL, 16, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '2.6', 'Technical Documentation', 'Are data models, ER diagrams and integration contracts documented and kept in sync with implementation?', 'technical', 1.0, TRUE, 'Yes', 17, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '2.7', 'Technical Documentation', 'Are known issues, limitations and technical debt items documented with owners and target dates?', 'technical', 1.0, TRUE, 'Maintained by Clients', 18, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '3.1', 'Data & Storage Design', 'Are data models and DB schemas appropriate for the workload and aligned to domain concepts?', 'technical', 1.0, TRUE, 'Yes', 19, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '3.2', 'Data & Storage Design', 'Are indexing, partitioning and sharding strategies adequate for expected scale and query patterns?', 'technical', 1.0, TRUE, 'Yes', 20, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '3.3', 'Data & Storage Design', 'Are critical queries reviewed and optimized using execution plans and performance metrics?', 'technical', 1.0, TRUE, 'Yes', 21, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '3.4', 'Data & Storage Design', 'Are backup and restore strategies defined, tested and documented for each data store?', 'technical', 1.0, TRUE, 'Yes', 22, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '3.5', 'Data & Storage Design', 'Are data retention, archival and purging policies defined and implemented in line with compliance needs?', 'technical', 1.0, TRUE, 'Yes', 23, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '3.6', 'Data & Storage Design', 'Is database security in place (RBAC, least privilege, encryption at rest, network controls, masking where needed)?', 'technical', 1.0, TRUE, 'Maintained by Clients', 24, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '3.7', 'Data & Storage Design', 'Is replication or high availability configured where required?', 'technical', 1.0, TRUE, 'Yes', 25, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '3.8', 'Data & Storage Design', 'Is data migration or integration strategy defined, including mapping, reconciliation and cutover plans?', 'technical', 1.0, TRUE, NULL, 26, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '3.9', 'Data & Storage Design', 'Are data quality checks and constraints in place (not-null, referential integrity, validation rules)?', 'technical', 1.0, TRUE, 'Yes', 27, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '4.1', 'Security Architecture', 'Is sensitive data (passwords, tokens, keys, PII, financial data) encrypted in transit and at rest?', 'technical', 1.0, TRUE, 'Yes. As per clients data classification document, data that PDH recevies has no need for encryption', 28, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '4.2', 'Security Architecture', 'Are authentication mechanisms aligned with enterprise standards (SSO, OAuth2/OIDC, MFA where required)?', 'technical', 1.0, TRUE, NULL, 29, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '4.3', 'Security Architecture', 'Is authorization based on least privilege using well-defined roles and permissions (RBAC/ABAC)?', 'technical', 1.0, TRUE, 'Client controlled', 30, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '4.4', 'Security Architecture', 'Are secrets stored in an approved secrets vault and never hardcoded or committed to source control?', 'technical', 1.0, TRUE, 'Clinet controlled. We use service accounts to execute the jobs.', 31, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '4.5', 'Security Architecture', 'Are input validation, output encoding and security headers implemented to prevent common attacks?', 'technical', 1.0, TRUE, 'Input validation is being done. Output encoding and sending files to downstream is handled by MFT team on clinet side', 32, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '4.6', 'Security Architecture', 'Are checks in place for common vulnerabilities (XSS, SQL injection, CSRF, SSRF, insecure deserialization, etc.)?', 'technical', 1.0, TRUE, 'NA, Maintainted by Clients', 33, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '4.7', 'Security Architecture', 'Are third-party dependencies and container images regularly scanned and updated for vulnerabilities?', 'technical', 1.0, TRUE, NULL, 34, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '4.8', 'Security Architecture', 'Is HTTPS/TLS enforced for all external and internal communications where appropriate?', 'technical', 1.0, TRUE, NULL, 35, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '4.9', 'Security Architecture', 'Are security-relevant events logged without leaking sensitive data?', 'technical', 1.0, TRUE, NULL, 36, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '4.1', 'Security Architecture', 'Are security reviews and tests (SAST, DAST, penetration tests where applicable) planned and tracked?', 'technical', 1.0, TRUE, NULL, 37, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '5.1', 'Code Quality & Standards', 'Is the codebase following agreed coding standards, naming conventions and folder structure?', 'technical', 1.0, TRUE, 'Yes', 38, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '5.2', 'Code Quality & Standards', 'Are peer reviews or pull-request reviews performed for all non-trivial changes?', 'technical', 1.0, TRUE, 'Yes', 39, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '5.3', 'Code Quality & Standards', 'Are hardcoded values, credentials and environment-specific parameters avoided and externalized to configuration or vaults?', 'technical', 1.0, TRUE, 'Yes', 40, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '5.4', 'Code Quality & Standards', 'Is error handling consistent, with meaningful messages and no silent failures?', 'technical', 1.0, TRUE, 'Yes', 41, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '5.5', 'Code Quality & Standards', 'Are reusable components and shared libraries used instead of copy-paste and duplication?', 'technical', 1.0, TRUE, 'Yes', 42, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '5.6', 'Code Quality & Standards', 'Are unit tests present for core logic with meaningful assertions and acceptable coverage?', 'technical', 1.0, TRUE, 'Yes', 43, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '5.7', 'Code Quality & Standards', 'Is version control used effectively (branching strategy, tagging, pull requests, release branches)?', 'technical', 1.0, TRUE, 'Yes', 44, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '5.8', 'Code Quality & Standards', 'Are static analysis tools and linters enabled and free of critical issues before merging?', 'technical', 1.0, TRUE, 'No', 45, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '5.9', 'Code Quality & Standards', 'Is dead code, unused configuration and feature flags regularly cleaned up?', 'technical', 1.0, TRUE, 'Yes', 46, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '5.1', 'Code Quality & Standards', 'Is the code structured to support testability and extension (dependency injection, interfaces, clear boundaries)?', 'technical', 1.0, TRUE, 'Yes', 47, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '6.1', 'Testing & Coverage', 'Is there a documented test strategy covering unit, integration, system, UAT, regression and smoke tests?', 'technical', 1.0, TRUE, 'Yes', 48, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '6.2', 'Testing & Coverage', 'Are test cases, test data and expected results documented and traceable to requirements or user stories?', 'technical', 1.0, TRUE, 'Yes', 49, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '6.3', 'Testing & Coverage', 'Are automated test suites integrated with CI/CD and run on every build or pull request for critical components?', 'technical', 1.0, TRUE, 'No', 50, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '6.4', 'Testing & Coverage', 'Is test coverage measured and are minimum thresholds defined for important modules?', 'technical', 1.0, TRUE, 'Yes', 51, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '6.5', 'Testing & Coverage', 'Are non-functional tests (performance, load, soak, security, failover) planned and executed where required?', 'technical', 1.0, TRUE, 'Yes', 52, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '6.6', 'Testing & Coverage', 'Are test environments representative of production in terms of configuration and integrations?', 'technical', 1.0, TRUE, 'Yes', 53, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '6.7', 'Testing & Coverage', 'Is defect tracking in place with clear ownership, priority and resolution SLAs?', 'technical', 1.0, TRUE, 'Yes', 54, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '7.1', 'DevSecOps', 'Is a CI/CD pipeline implemented for build, test, security scans and deployment?', 'technical', 1.0, TRUE, 'Yes', 55, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '7.2', 'DevSecOps', 'Are environment configurations (Dev, QA, Pre-Prod, Prod) parameterized, separated and managed securely?', 'technical', 1.0, TRUE, 'Yes', 56, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '7.3', 'DevSecOps', 'Is a clear rollback or hotfix strategy defined and tested for failed deployments?', 'technical', 1.0, TRUE, 'Yes', 57, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '7.4', 'DevSecOps', 'Is infrastructure-as-code (Terraform, ARM/Bicep, CloudFormation, Ansible, Helm, etc.) used where applicable?', 'technical', 1.0, TRUE, 'Mainatined by clinets', 58, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '7.5', 'DevSecOps', 'Are deployment scripts, IaC templates and pipeline definitions version-controlled and peer-reviewed?', 'technical', 1.0, TRUE, 'Yes', 59, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '7.6', 'DevSecOps', 'Are SAST, DAST, software composition analysis and container image scans integrated into pipelines with gating policies?', 'technical', 1.0, TRUE, NULL, 60, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '7.7', 'DevSecOps', 'Are secrets and credentials in pipelines managed through a secure secrets store and never embedded in code?', 'technical', 1.0, TRUE, 'Yes', 61, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '7.8', 'DevSecOps', 'Are backups, restore procedures and DR runbooks validated through regular drills or simulations?', 'technical', 1.0, TRUE, 'Maintained by Clients', 62, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '7.9', 'DevSecOps', 'Are CI/CD tools themselves secured with access control, audit trails and least-privilege permissions?', 'technical', 1.0, TRUE, 'Maintained by Clients', 63, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '8.1', 'Environments & Infrastructure', 'Is Dev/QA/UAT/Pre-Prod/Prod parity maintained for key components and configurations?', 'technical', 1.0, TRUE, 'Yes', 64, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '8.2', 'Environments & Infrastructure', 'Are environments provisioned and updated via IaC and configuration management tools?', 'technical', 1.0, TRUE, 'Maintained by Clients', 65, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '8.3', 'Environments & Infrastructure', 'Are capacities right-sized with headroom for growth and peak loads, and is auto-scaling used where relevant?', 'technical', 1.0, TRUE, 'Maintained by Clients', 66, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '8.4', 'Environments & Infrastructure', 'Are recent build or environment failures analyzed with RCA and corrective actions tracked?', 'technical', 1.0, TRUE, 'Maintained by Clients', 67, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '8.5', 'Environments & Infrastructure', 'Are high-availability and resilience mechanisms in place (clusters, load balancers, multi-AZ or multi-node)?', 'technical', 1.0, TRUE, 'Maintained by Clients', 68, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '8.6', 'Environments & Infrastructure', 'Are network configurations (VPC/VNet, firewalls, security groups, ingress/egress rules, VPN) reviewed and documented?', 'technical', 1.0, TRUE, 'Maintained by Clients', 69, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '8.7', 'Environments & Infrastructure', 'Are environment-specific settings externalized and managed securely (no secrets in flat files checked into Git)?', 'technical', 1.0, TRUE, 'Yes', 70, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '9.1', 'Operational Readiness & Reliability', 'Is centralized, structured logging in place with correlation IDs to trace requests across services?', 'technical', 1.0, TRUE, NULL, 71, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '9.2', 'Operational Readiness & Reliability', 'Are metrics and dashboards defined for key SLIs such as latency, error rate, throughput and resource usage?', 'technical', 1.0, TRUE, NULL, 72, NOW());
