    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '9.4', 'Operational Readiness & Reliability', 'Is there a clear on-call model and escalation matrix for production incidents?', 'technical', 1.0, TRUE, 'Yes', 74, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '9.5', 'Operational Readiness & Reliability', 'Are support processes, SOPs, runbooks and troubleshooting guides documented and maintained?', 'technical', 1.0, TRUE, 'Yes', 75, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '9.6', 'Operational Readiness & Reliability', 'Has the system passed an agreed go-live or operational readiness checklist?', 'technical', 1.0, TRUE, 'Yes', 76, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '9.7', 'Operational Readiness & Reliability', 'Are incident management and RCA processes defined with follow-up actions for recurring issues?', 'technical', 1.0, TRUE, 'Yes', 77, NOW());
    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '10.1', 'Compliance & Governance', 'Are licensing requirements for all third-party tools, libraries and platforms understood and compliant?', 'technical', 1.0, TRUE, 'Maintained by Clients', 78, NOW());
