    INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (cl_id, '12.3', 'APIs, Integrations & Messaging', 'Are API gateways or integration platforms configured for authentication, routing, throttling and logging?', 'technical', 1.0, TRUE, NULL, 92, NOW());
