  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (del_cl_id, '1.3', 'Scope, Planning & Governance', 'Is the project plan (milestones, releases, critical path) realistic, updated, and communicated?', 'delivery', 1.0, TRUE, 'Yes', 2, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (del_cl_id, '1.4', 'Scope, Planning & Governance', 'Is governance cadence followed (status reviews, steering committee, reporting)?', 'delivery', 1.0, TRUE, 'Yes', 3, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (del_cl_id, '1.5', 'Scope, Planning & Governance', 'Are decision logs and action items tracked with owners and due dates?', 'delivery', 1.0, TRUE, 'Yes', 4, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (del_cl_id, '2.1', 'Delivery Health', 'Are milestones, sprints, and releases on track against plan (schedule variance within tolerance)?', 'delivery', 1.0, TRUE, 'Yes', 5, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (del_cl_id, '2.2', 'Delivery Health', 'Are deliverables peer-reviewed and meeting acceptance / Definition of Done criteria?', 'delivery', 1.0, TRUE, 'Yes', 6, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (del_cl_id, '2.3', 'Delivery Health', 'Are blockers, technical debt, and rework under control and visible in plans?', 'delivery', 1.0, TRUE, 'Yes', 7, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (del_cl_id, '2.4', 'Delivery Health', 'Is release planning (scope, dates, dependencies) clear and agreed with stakeholders?', 'delivery', 1.0, TRUE, 'Yes', 8, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (del_cl_id, '3.1', 'Requirements & Customer Alignment', 'Are requirements / user stories clear, prioritized, approved, and version-controlled?', 'delivery', 1.0, TRUE, 'Yes', 9, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (del_cl_id, '3.2', 'Requirements & Customer Alignment', 'Are acceptance criteria and non-functional requirements defined and agreed with the customer?', 'delivery', 1.0, TRUE, 'Yes', 10, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (del_cl_id, '3.3', 'Requirements & Customer Alignment', 'Are backlog refinement, demos, and walk-throughs regularly done with key stakeholders?', 'delivery', 1.0, TRUE, 'Yes', 11, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (del_cl_id, '3.4', 'Requirements & Customer Alignment', 'Are stakeholder communications timely, transparent, and documented?', 'delivery', 1.0, TRUE, 'Yes', 12, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (del_cl_id, '3.5', 'Requirements & Customer Alignment', 'Are there any customer escalations, dissatisfaction signals, or relationship risks?', 'delivery', 1.0, TRUE, 'No', 13, NOW());
