  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (del_cl_id, '4.2', 'Risks, Issues & Escalations', 'Are mitigations and contingency plans defined for high / critical risks?', 'delivery', 1.0, TRUE, 'Yes', 15, NOW());
