  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (tec_cl_id, '9.3', 'Operational Readiness & Reliability', 'Are alerts configured with meaningful thresholds, noise reduction and linked runbooks?', 'technical', 1.0, TRUE, NULL, 73, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (tec_cl_id, '9.4', 'Operational Readiness & Reliability', 'Is there a clear on-call model and escalation matrix for production incidents?', 'technical', 1.0, TRUE, 'Yes', 74, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (tec_cl_id, '9.5', 'Operational Readiness & Reliability', 'Are support processes, SOPs, runbooks and troubleshooting guides documented and maintained?', 'technical', 1.0, TRUE, 'Yes', 75, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (tec_cl_id, '9.6', 'Operational Readiness & Reliability', 'Has the system passed an agreed go-live or operational readiness checklist?', 'technical', 1.0, TRUE, 'Yes', 76, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (tec_cl_id, '9.7', 'Operational Readiness & Reliability', 'Are incident management and RCA processes defined with follow-up actions for recurring issues?', 'technical', 1.0, TRUE, 'Yes', 77, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (tec_cl_id, '10.1', 'Compliance & Governance', 'Are licensing requirements for all third-party tools, libraries and platforms understood and compliant?', 'technical', 1.0, TRUE, 'Maintained by Clients', 78, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (tec_cl_id, '10.2', 'Compliance & Governance', 'Is the solution compliant with applicable data protection and privacy regulations and internal policies?', 'technical', 1.0, TRUE, 'Yes', 79, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (tec_cl_id, '10.3', 'Compliance & Governance', 'Are audit logs enabled for critical business and security events and stored securely with defined retention?', 'technical', 1.0, TRUE, 'Maintained by Clients', 80, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (tec_cl_id, '10.4', 'Compliance & Governance', 'Are data classification and handling rules applied to PII and other sensitive data with appropriate controls?', 'technical', 1.0, TRUE, 'Yes', 81, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (tec_cl_id, '10.5', 'Compliance & Governance', 'Are data retention, archival and deletion policies defined, implemented and aligned with legal requirements?', 'technical', 1.0, TRUE, 'Yes', 82, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (tec_cl_id, '10.6', 'Compliance & Governance', 'Are access reviews, segregation of duties and approval workflows in place for privileged operations and changes?', 'technical', 1.0, TRUE, 'Maintained by Clients', 83, NOW());
