  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (tec_cl_id, '11.2', 'Performance, Scalability & Resilience', 'Have load, stress and endurance tests been executed using realistic workloads and data volumes?', 'technical', 1.0, TRUE, 'Yes', 85, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (tec_cl_id, '11.3', 'Performance, Scalability & Resilience', 'Are performance bottlenecks identified, profiled and tracked with action items?', 'technical', 1.0, TRUE, 'Yes', 86, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (tec_cl_id, '11.4', 'Performance, Scalability & Resilience', 'Are caching, batching and asynchronous processing used where appropriate to improve performance?', 'technical', 1.0, TRUE, NULL, 87, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (tec_cl_id, '11.5', 'Performance, Scalability & Resilience', 'Are resiliency patterns such as timeouts, retries, circuit breakers and bulkheads implemented and tested?', 'technical', 1.0, TRUE, NULL, 88, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (tec_cl_id, '11.6', 'Performance, Scalability & Resilience', 'Is capacity planning done for peak load, growth and burst scenarios with monitoring to validate assumptions?', 'technical', 1.0, TRUE, 'Yes', 89, NOW());
