  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (tec_cl_id, '12.2', 'APIs, Integrations & Messaging', 'Are API and message contracts documented and versioned (OpenAPI, AsyncAPI, schema registry, etc.)?', 'technical', 1.0, TRUE, NULL, 91, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (tec_cl_id, '12.3', 'APIs, Integrations & Messaging', 'Are API gateways or integration platforms configured for authentication, routing, throttling and logging?', 'technical', 1.0, TRUE, NULL, 92, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (tec_cl_id, '12.4', 'APIs, Integrations & Messaging', 'Are error handling, timeouts, retries and idempotency behaviour defined and implemented for all integrations?', 'technical', 1.0, TRUE, 'Yes', 93, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (tec_cl_id, '12.5', 'APIs, Integrations & Messaging', 'Are contract tests or automated integration tests in place for critical APIs, queues and topics?', 'technical', 1.0, TRUE, NULL, 94, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (tec_cl_id, '12.6', 'APIs, Integrations & Messaging', 'Are message schemas, routing keys, queues and topics documented and governed to avoid breaking changes?', 'technical', 1.0, TRUE, NULL, 95, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (tec_cl_id, '13.1', 'User Experience & Accessibility', 'Are key user journeys and personas identified and tested end-to-end?', 'technical', 1.0, TRUE, NULL, 96, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (tec_cl_id, '13.2', 'User Experience & Accessibility', 'Is the UI consistent with the design system or style guide for layout, typography and interactions?', 'technical', 1.0, TRUE, NULL, 97, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (tec_cl_id, '13.3', 'User Experience & Accessibility', 'Is the application responsive and usable across supported devices, browsers and screen sizes?', 'technical', 1.0, TRUE, NULL, 98, NOW());
  INSERT INTO checklist_items (checklist_id, item_code, area, question, category, weight, is_required, expected_evidence, "order", created_at) VALUES (tec_cl_id, '13.4', 'User Experience & Accessibility', 'Are accessibility guidelines (for example WCAG 2.1) considered and tested where required?', 'technical', 1.0, TRUE, NULL, 99, NOW());
